/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWMortalidade-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&MorFilCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filial") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MorFilCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'MORALOUNIPRONOM' &MorAloUniProNom1.FromString(&GridStateDynamicFilter.Value) If not &MorAloUniProNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tanque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MorAloUniProNom1 EndIf Case &DynamicFiltersSelector1 = !'MORALOLOTNRO' &MorAloLotNro1.FromString(&GridStateDynamicFilter.Value) If not &MorAloLotNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lote" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MorAloLotNro1) EndIf Case &DynamicFiltersSelector1 = !'MORTIP' &MorTip1.FromString(&GridStateDynamicFilter.Value) If not &MorTip1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &MorTip1.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &MorTip1.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector1 = !'MORALOLOTCIC' &MorAloLotCic1.FromString(&GridStateDynamicFilter.Value) If not &MorAloLotCic1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ciclo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MorAloLotCic1) EndIf Case &DynamicFiltersSelector1 = !'MORALOLIN' &MorAloLin1.FromString(&GridStateDynamicFilter.Value) If not &MorAloLin1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Linha" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MorAloLin1 EndIf Case &DynamicFiltersSelector1 = !'MORDTA' &MorDta1.FromString(&GridStateDynamicFilter.Value) &MorDta_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &MorDta1.IsEmpty() OR not &MorDta_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Período" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &MorDta1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &MorDta_To1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'MORALOUNIPRONOM' &MorAloUniProNom2.FromString(&GridStateDynamicFilter.Value) If not &MorAloUniProNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tanque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MorAloUniProNom2 EndIf Case &DynamicFiltersSelector2 = !'MORALOLOTNRO' &MorAloLotNro2.FromString(&GridStateDynamicFilter.Value) If not &MorAloLotNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lote" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MorAloLotNro2) EndIf Case &DynamicFiltersSelector2 = !'MORTIP' &MorTip2.FromString(&GridStateDynamicFilter.Value) If not &MorTip2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &MorTip2.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &MorTip2.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector2 = !'MORALOLOTCIC' &MorAloLotCic2.FromString(&GridStateDynamicFilter.Value) If not &MorAloLotCic2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ciclo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MorAloLotCic2) EndIf Case &DynamicFiltersSelector2 = !'MORALOLIN' &MorAloLin2.FromString(&GridStateDynamicFilter.Value) If not &MorAloLin2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Linha" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MorAloLin2 EndIf Case &DynamicFiltersSelector2 = !'MORDTA' &MorDta2.FromString(&GridStateDynamicFilter.Value) &MorDta_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &MorDta2.IsEmpty() OR not &MorDta_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Período" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &MorDta2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &MorDta_To2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'MORALOUNIPRONOM' &MorAloUniProNom3.FromString(&GridStateDynamicFilter.Value) If not &MorAloUniProNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tanque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MorAloUniProNom3 EndIf Case &DynamicFiltersSelector3 = !'MORALOLOTNRO' &MorAloLotNro3.FromString(&GridStateDynamicFilter.Value) If not &MorAloLotNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lote" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MorAloLotNro3) EndIf Case &DynamicFiltersSelector3 = !'MORTIP' &MorTip3.FromString(&GridStateDynamicFilter.Value) If not &MorTip3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &MorTip3.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &MorTip3.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector3 = !'MORALOLOTCIC' &MorAloLotCic3.FromString(&GridStateDynamicFilter.Value) If not &MorAloLotCic3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ciclo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MorAloLotCic3) EndIf Case &DynamicFiltersSelector3 = !'MORALOLIN' &MorAloLin3.FromString(&GridStateDynamicFilter.Value) If not &MorAloLin3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Linha" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MorAloLin3 EndIf Case &DynamicFiltersSelector3 = !'MORDTA' &MorDta3.FromString(&GridStateDynamicFilter.Value) &MorDta_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &MorDta3.IsEmpty() OR not &MorDta_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Período" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &MorDta3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &MorDta_To3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&VisibleColumnCount = 0 If &Session.Get(!'WWMortalidadeColumnsSelector') <> '' &ColumnsSelectorXML = &Session.Get(!'WWMortalidadeColumnsSelector') &ColumnsSelector.FromXml(&ColumnsSelectorXML) Else Do 'InitializeColumnsSelector' EndIf
For &ColumnsSelector_Column in &ColumnsSelector.Columns If &ColumnsSelector_Column.IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = GetMessageText(iif(&ColumnsSelector_Column.DisplayName.IsEmpty(), &ColumnsSelector_Column.ColumnName, &ColumnsSelector_Column.DisplayName)) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Color = 11 &VisibleColumnCount += 1 EndIf EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod MorAloLotNro (MorDta) MorAloUniProNom using DSWWMortalidade(&DynamicFiltersSelector1, &MorAloUniProNom1, &MorAloLotNro1, &MorTip1, &MorAloLotCic1, &MorAloLin1 , &MorDta1, &MorDta_To1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &MorAloUniProNom2, &MorAloLotNro2 , &MorTip2, &MorAloLotCic2, &MorAloLin2, &MorDta2, &MorDta_To2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &MorAloUniProNom3, &MorAloLotNro3, &MorTip3, &MorAloLotCic3, &MorAloLin3 , &MorDta3, &MorDta_To3, &MorFilCod)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &VisibleColumnCount = 0 If &ColumnsSelector.Columns.Item(1).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = MorFilCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(2).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = MorAloUniProNom &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(3).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(MorAloLotNro) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(4).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(MorAloLotCic) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(5).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = MorTip.EnumerationDescription() &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(6).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = MorDta &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(7).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = MorQtd &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(8).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = MorAloLin &VisibleColumnCount += 1 EndIf
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorFilCod", '', !'Filial', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorAloUniProNom", '', !'Tanque', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorAloLotNro", '', !'Lote', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorAloLotCic", '', !'Ciclo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorTip", '', !'Tipo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorDta", '', !'Data', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorQtd", '', !'Qtde', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MorAloLin", '', !'Linha', False, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'WWMortalidadeColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWMortalidadeGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWMortalidadeGridState")) Else &GridState.FromXml(&Session.Get(!"WWMortalidadeGridState")) Endif
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"MORFILCOD" &MorFilCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
